interface ReadCardProps {
  fn: AbiFunction;
  abi: unknown[];
  contractAddress: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  publicClient: any;
  onCallResult: ContractInteractionProps['onCallResult'];
}

function ReadFunctionCard({
  fn,
  abi,
  contractAddress,
  publicClient,
  onCallResult,
}: ReadCardProps) {
  const [inputs, setInputs] = useState<Record<string, string>>({});
  const [result, setResult] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const handleInputChange = useCallback(
    (paramName: string, value: string) => {
      setInputs((prev) => ({ ...prev, [paramName]: value }));
    },
    [],
  );

  const handleCall = useCallback(async () => {
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const args = fn.inputs.map((p) =>
        parseInputValue(inputs[p.name] ?? '', p.type),
      );

      const data = await publicClient.readContract({
        address: contractAddress as `0x${string}`,
        abi,
        functionName: fn.name,
        args: args.length > 0 ? args : undefined,
      });

      const formatted = formatOutputValue(data);
      setResult(formatted);

      onCallResult({
        type: 'call',
        status: 'success',
        message: `${fn.name}() → ${formatted}`,
        details: { contractName: fn.name },
      });
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      setError(msg);

      onCallResult({
        type: 'call',
        status: 'error',
        message: `${fn.name}() failed: ${msg}`,
        details: { errors: [msg] },
      });
    } finally {
      setLoading(false);
    }
  }, [fn, inputs, abi, contractAddress, publicClient, onCallResult]);

  return (
    <div className="rounded-lg border border-gray-700 bg-gray-800 p-3 space-y-2">
      <p className="text-sm font-mono text-cyan-300">{fn.name}()</p>

      {fn.inputs.map((param) => (
        <FunctionInput
          key={param.name || param.type}
          param={param}
          value={inputs[param.name] ?? ''}
          onChange={(v) => handleInputChange(param.name, v)}
        />
      ))}

      <button
        onClick={handleCall}
        disabled={loading}
